diff --git a/llvm/lib/Transforms/InstCombine/InstCombineCasts.cpp b/llvm/lib/Transforms/InstCombine/InstCombineCasts.cpp
index fdef49e310f8..20e8404a2cdc 100644
--- a/llvm/lib/Transforms/InstCombine/InstCombineCasts.cpp
+++ b/llvm/lib/Transforms/InstCombine/InstCombineCasts.cpp
@@ -849,6 +849,22 @@ Instruction *InstCombinerImpl::visitTrunc(TruncInst &Trunc) {
         return new ICmpInst(ICmpInst::Predicate::ICMP_EQ, X, Zero);
       }
     }
+    {
+      const APInt *C;
+      if (!SrcTy->isVectorTy() &&
+          match(Src, m_LShr(m_APInt(C), m_Value(X)))) {
+        if (C->isPowerOf2()) {
+          // trunc (lshr C, X) to i1 --> X == log2(C)
+          Constant *Log2C = ConstantInt::get(X->getType(), C->exactLogBase2());
+          return new ICmpInst(ICmpInst::ICMP_EQ, X, Log2C);
+        }
+        // General case: trunc (lshr C, X) to i1 --> (C & (1 << X)) != 0
+        Constant *One = ConstantInt::get(SrcTy, APInt(SrcWidth, 1));
+        Value *Shl = Builder.CreateShl(One, X);
+        Value *And = Builder.CreateAnd(ConstantInt::get(SrcTy, *C), Shl);
+        return new ICmpInst(ICmpInst::ICMP_NE, And, Zero);
+      }
+    }

     if (Trunc.hasNoUnsignedWrap() || Trunc.hasNoSignedWrap()) {
       Value *X, *Y;

